#include<bits/stdc++.h>using namespace std; int a[2005];int b[100005];int cur[2005];  int main() {    ios::sync_with_stdio(false);    cin.tie(0);        int t;    cin >> t;    while (t--) {        int n, k, d;        cin >> n >> k >> d;                for (int i = 1; i <= n; i++) {            cin >> a[i];        }                for (int i = 0; i < k; i++) {            cin >> b[i];        }         for (int i = 1; i <= n; i++) {            cur[i] = a[i];        }                int ans = 0;        for (int day = 0; day < min(d, 2*n + 5); day++) {            int match = 0;            for (int i = 1; i <= n; i++) {                if (cur[i] == i) {                    match++;                }            }                    int remaining = d - day - 1;             int score = match + remaining / 2;            ans = max(ans, score);            for (int i = 1; i <= b[day % k]; i++) {                cur[i]++;            }        }                cout << ans << "\n";    }        return 0;}